import{_ as r,o as t,c as o,ak as i}from"./chunks/framework.pkL_v29K.js";const u=JSON.parse('{"title":"Requirements","description":"","frontmatter":{},"headers":[],"relativePath":"dotpi-tools/requirements.md","filePath":"dotpi-tools/requirements.md"}'),s={name:"dotpi-tools/requirements.md"};function a(n,e,d,l,p,c){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to “Requirements”">​</a></h1><h2 id="developer-machine" tabindex="-1">Developer machine <a class="header-anchor" href="#developer-machine" aria-label="Permalink to “Developer machine”">​</a></h2><p>For the developer machine, we need a host that is capable of running:</p><ul><li><code>bash</code></li><li><code>perl</code></li><li><code>ssh</code></li><li><code>Node.js</code></li></ul><p>We tested MacOS, Linux and Windows Subsystem for Linux (WSL). Pull requests are welcome for other systems.</p><h2 id="raspberry-pi-computers" tabindex="-1">Raspberry Pi computers <a class="header-anchor" href="#raspberry-pi-computers" aria-label="Permalink to “Raspberry Pi computers”">​</a></h2><p><em>dotpi</em> runs with Raspberry Pi version 3 and 4 (and should work on version 5 but has not been tested yet, any feedback welcome).</p><p><em>dotpi</em> systems installed on Raspberry Pis are created on top of <code>Raspberry Pi OS</code>. Currently the underlying Debian distribution is <code>Bookworm</code>. <em>dotpi</em> still runs with the previous distribution (<code>Bullseye</code>) but it is not supported.</p><p>Additionally, <em>dotpi</em> supports the <code>Lite</code> version (minimal, without graphical interface) of <code>Raspberry Pi OS</code>. It should work with other versions but it is untested.</p>',9)])])}const h=r(s,[["render",a]]);export{u as __pageData,h as default};
